// ─── MYCROFT: Input Parser & Validator ───────────────────────────────────────
const body = $input.first().json.body || $input.first().json;

// Apply defaults and parse types
const input = {
  company:             String(body.company              || 'Unknown Company'),
  ticker:              String(body.ticker               || 'N/A').toUpperCase(),
  revenue_growth:      parseFloat(body.revenue_growth   ?? 0.15),
  sentiment_score:     parseFloat(body.sentiment_score  ?? 0.50),
  risk_appetite:       String(body.risk_appetite         || 'medium').toLowerCase(),
  time_horizon:        String(body.time_horizon          || '1year').toLowerCase(),
  current_price:       parseFloat(body.current_price     ?? 100),
  pe_ratio:            parseFloat(body.pe_ratio           ?? 25),
  debt_equity:         parseFloat(body.debt_equity        ?? 0.50),
  market_cap_billions: parseFloat(body.market_cap_billions ?? 10)
};

// Validation rules
const errors = [];
if (input.revenue_growth < -1   || input.revenue_growth > 20)  errors.push('revenue_growth must be between -1.0 and 20.0');
if (input.sentiment_score < 0   || input.sentiment_score > 1)  errors.push('sentiment_score must be 0–1');
if (!['low','medium','high'].includes(input.risk_appetite))     errors.push('risk_appetite must be low | medium | high');
if (input.pe_ratio < 0)                                         errors.push('pe_ratio must be positive');
if (input.debt_equity < 0)                                      errors.push('debt_equity must be positive');

// Normalise time horizon
if (!['3month','1year','5year'].includes(input.time_horizon)) input.time_horizon = '1year';

if (errors.length > 0) throw new Error('Validation Failed: ' + errors.join(' | '));

// Generate unique simulation ID
const rand = Math.random().toString(36).substr(2, 6).toUpperCase();
const simulation_id = `SIM-${Date.now()}-${rand}`;

return [{ json: { ...input, simulation_id, timestamp: new Date().toISOString() } }];

// ─── SIMULATION 1: Growth vs Sentiment Tradeoff ──────────────────────────────
// Core Principle: If fundamentals and market sentiment diverge → detect the conflict
const data   = $input.first().json;
const growth    = data.revenue_growth;
const sentiment = data.sentiment_score;

// Level classifiers
const growthLevel    = growth    >= 0.25 ? 'HIGH' : growth    >= 0.10 ? 'MEDIUM' : 'LOW';
const sentimentLevel = sentiment >= 0.65 ? 'HIGH' : sentiment >= 0.40 ? 'MEDIUM' : 'LOW';

// 3×3 Signal Matrix — each cell is a full decision profile
const signalMatrix = {
  HIGH_HIGH:   { signal:'STRONG_BUY',       confidence:0.88, risk:'LOW',         short_term:'+15 to +25%',  long_term:'+60 to +120%', description:'Both fundamentals and market conviction are aligned — ideal setup.' },
  HIGH_MEDIUM: { signal:'BUY',              confidence:0.72, risk:'LOW_MEDIUM',  short_term:'+8 to +15%',   long_term:'+40 to +80%',  description:'Strong fundamentals; market is starting to recognise the value.' },
  HIGH_LOW:    { signal:'FUNDAMENTAL_BUY',  confidence:0.61, risk:'MEDIUM',      short_term:'-5 to +5%',    long_term:'+30 to +70%',  description:'Market undervaluing strong fundamentals — contrarian value play.' },
  MEDIUM_HIGH: { signal:'HOLD_WATCH',       confidence:0.55, risk:'MEDIUM',      short_term:'+5 to +12%',   long_term:'+15 to +35%',  description:'Sentiment slightly ahead of fundamentals — monitor for convergence.' },
  MEDIUM_MEDIUM:{ signal:'HOLD',            confidence:0.65, risk:'MEDIUM',      short_term:'0 to +8%',     long_term:'+10 to +25%',  description:'Balanced but lacks a strong catalyst either way.' },
  MEDIUM_LOW:  { signal:'UNDERPERFORM',     confidence:0.60, risk:'MEDIUM_HIGH', short_term:'-5 to +5%',    long_term:'+5 to +15%',   description:'Adequate fundamentals dragged down by weak sentiment.' },
  LOW_HIGH:    { signal:'BUBBLE_RISK',      confidence:0.75, risk:'HIGH',        short_term:'+5 to +15%',   long_term:'-20 to 0%',    description:'DANGER: Sentiment massively disconnected from weak fundamentals.' },
  LOW_MEDIUM:  { signal:'SELL',             confidence:0.68, risk:'HIGH',        short_term:'-5 to -15%',   long_term:'-10 to +10%',  description:'Deteriorating fundamentals with fading sentiment support.' },
  LOW_LOW:     { signal:'STRONG_SELL',      confidence:0.82, risk:'VERY_HIGH',   short_term:'-15 to -30%',  long_term:'-30 to -10%',  description:'Both fundamentals and market sentiment fully bearish.' }
};

const matrixKey = `${growthLevel}_${sentimentLevel}`;
const result    = signalMatrix[matrixKey];

// Conflict & Bubble Detection
const conflictDetected = (growthLevel === 'HIGH'   && sentimentLevel === 'LOW') ||
                         (growthLevel === 'LOW'    && sentimentLevel === 'HIGH');

const bubbleRiskScore =
  (growthLevel === 'LOW'    && sentimentLevel === 'HIGH')   ? 0.85 :
  (growthLevel === 'MEDIUM' && sentimentLevel === 'HIGH')   ? 0.48 :
  (growthLevel === 'LOW'    && sentimentLevel === 'MEDIUM') ? 0.35 : 0.12;

const correctionProbability =
  bubbleRiskScore > 0.70 ? 'HIGH (>65%)'  :
  bubbleRiskScore > 0.40 ? 'MEDIUM (30–65%)' : 'LOW (<30%)';

// Key Insight — human-readable narrative
let keyInsight;
if (growthLevel === 'HIGH' && sentimentLevel === 'LOW') {
  keyInsight = `⚠️ CONFLICT DETECTED: Strong ${Math.round(growth*100)}% revenue growth is being ignored by the market (sentiment ${(sentiment*100).toFixed(0)}%). Classic value opportunity — patience required.`;
} else if (growthLevel === 'LOW' && sentimentLevel === 'HIGH') {
  keyInsight = `🚨 BUBBLE RISK: High sentiment (${(sentiment*100).toFixed(0)}%) is NOT supported by ${Math.round(growth*100)}% growth. Correction probability is ${correctionProbability}.`;
} else {
  keyInsight = `${growthLevel} growth + ${sentimentLevel} sentiment → ${result.signal}. ${result.description}`;
}

return [{ json: {
  ...data,
  sim1_growth_sentiment: {
    simulation:        'GROWTH_VS_SENTIMENT',
    inputs:            { growth_rate: growth, sentiment_score: sentiment, growth_level: growthLevel, sentiment_level: sentimentLevel },
    output:            result,
    conflict_detected: conflictDetected,
    bubble_risk_score: bubbleRiskScore,
    correction_probability: correctionProbability,
    key_insight:       keyInsight
  }
} }];

// ─── SIMULATION 2: Risk Appetite Simulator ───────────────────────────────────
// Core Principle: Same stock → different decisions for different investor types
const data      = $input.first().json;
const riskLevel = data.risk_appetite;
const growth    = data.revenue_growth;
const sentiment = data.sentiment_score;
const pe        = data.pe_ratio;
const de        = data.debt_equity;

// Full investor profile definitions
const profiles = {
  low: {
    name: 'Conservative', icon: '🔵',
    growth_threshold:    0.15,
    sentiment_threshold: 0.60,
    pe_max:              25,
    de_max:              0.50,
    max_position_pct:    5,
    stop_loss_pct:       5,
    take_profit_pct:     12,
    preferred_horizon:   '3–5 years',
    max_drawdown:        '10%',
    description:         'Capital preservation is paramount. Prefers stable, established companies with low volatility and dividends.'
  },
  medium: {
    name: 'Balanced', icon: '🟢',
    growth_threshold:    0.10,
    sentiment_threshold: 0.45,
    pe_max:              40,
    de_max:              0.80,
    max_position_pct:    10,
    stop_loss_pct:       10,
    take_profit_pct:     25,
    preferred_horizon:   '1–3 years',
    max_drawdown:        '20%',
    description:         'Balanced growth and protection. Accepts moderate volatility in exchange for higher long-term returns.'
  },
  high: {
    name: 'Aggressive', icon: '🟠',
    growth_threshold:    0.05,
    sentiment_threshold: 0.35,
    pe_max:              80,
    de_max:              1.50,
    max_position_pct:    20,
    stop_loss_pct:       20,
    take_profit_pct:     60,
    preferred_horizon:   '6–18 months',
    max_drawdown:        '40%',
    description:         'Maximum growth orientation. High volatility tolerance. Seeks asymmetric upside opportunities.'
  }
};

const profile = profiles[riskLevel];

// Evaluate this stock against the selected profile — 4 weighted criteria
const criteria = [
  { name: 'Revenue Growth',  pass: growth    >= profile.growth_threshold,    actual: `${Math.round(growth*100)}%`,        required: `≥ ${Math.round(profile.growth_threshold*100)}%`,   weight: 0.30 },
  { name: 'Market Sentiment',pass: sentiment >= profile.sentiment_threshold, actual: sentiment.toFixed(2),                required: `≥ ${profile.sentiment_threshold.toFixed(2)}`,      weight: 0.25 },
  { name: 'P/E Ratio',       pass: pe        <= profile.pe_max,               actual: pe.toFixed(1),                       required: `≤ ${profile.pe_max}`,                              weight: 0.25 },
  { name: 'Debt / Equity',   pass: de        <= profile.de_max,               actual: de.toFixed(2),                       required: `≤ ${profile.de_max}`,                              weight: 0.20 }
];

const weightedPassRate = criteria.reduce((sum, c) => sum + (c.pass ? c.weight : 0), 0);
const passCount        = criteria.filter(c => c.pass).length;

const recommendation =
  weightedPassRate >= 0.80 ? 'ENTER_FULL_POSITION'    :
  weightedPassRate >= 0.55 ? 'ENTER_PARTIAL_POSITION' :
  weightedPassRate >= 0.30 ? 'WATCHLIST_ONLY'         : 'AVOID';

// Cross-profile comparison — how does the SAME stock look to each investor type?
const crossProfileComparison = Object.entries(profiles).map(([level, p]) => {
  const criteriaScores = [
    { pass: growth    >= p.growth_threshold,    weight: 0.30 },
    { pass: sentiment >= p.sentiment_threshold, weight: 0.25 },
    { pass: pe        <= p.pe_max,              weight: 0.25 },
    { pass: de        <= p.de_max,              weight: 0.20 }
  ];
  const wpr = criteriaScores.reduce((s, c) => s + (c.pass ? c.weight : 0), 0);
  const rec = wpr >= 0.80 ? 'ENTER' : wpr >= 0.55 ? 'PARTIAL' : wpr >= 0.30 ? 'WATCH' : 'AVOID';
  return {
    risk_level:     level,
    investor_type:  p.name,
    fit_score_pct:  Math.round(wpr * 100),
    recommendation: rec,
    max_position:   `${p.max_position_pct}%`,
    stop_loss:      `${p.stop_loss_pct}%`,
    is_selected:    level === riskLevel
  };
});

const keyInsight = `${profile.icon} ${profile.name} investor → ${recommendation} | ${Math.round(weightedPassRate*100)}% criteria met (${passCount}/4 passed) | Max position: ${profile.max_position_pct}% | Stop-loss: ${profile.stop_loss_pct}%`;

return [{ json: {
  ...data,
  sim2_risk_appetite: {
    simulation:                'RISK_APPETITE',
    inputs:                    { risk_appetite: riskLevel, pe_ratio: pe, debt_equity: de, revenue_growth: growth, sentiment_score: sentiment },
    profile,
    criteria_evaluation:       criteria,
    weighted_pass_rate:        Math.round(weightedPassRate * 100) / 100,
    pass_count:                `${passCount}/4`,
    recommendation,
    cross_profile_comparison:  crossProfileComparison,
    key_insight:               keyInsight
  }
} }];

// ─── SIMULATION 3: Threshold Break Simulator ─────────────────────────────────
// Core Principle: At what exact point does the recommendation CHANGE?
const data             = $input.first().json;
const currentGrowth    = data.revenue_growth;
const currentSentiment = data.sentiment_score;

// Shared signal classifier (mirrors Sim1 logic)
function classify(g, s) {
  const gL = g >= 0.25 ? 'HIGH' : g >= 0.10 ? 'MEDIUM' : 'LOW';
  const sL = s >= 0.65 ? 'HIGH' : s >= 0.40 ? 'MEDIUM' : 'LOW';
  const m  = {
    HIGH_HIGH:'STRONG_BUY', HIGH_MEDIUM:'BUY', HIGH_LOW:'FUNDAMENTAL_BUY',
    MEDIUM_HIGH:'HOLD_WATCH', MEDIUM_MEDIUM:'HOLD', MEDIUM_LOW:'UNDERPERFORM',
    LOW_HIGH:'BUBBLE_RISK', LOW_MEDIUM:'SELL', LOW_LOW:'STRONG_SELL'
  };
  return m[`${gL}_${sL}`] || 'HOLD';
}

const baseRecommendation = classify(currentGrowth, currentSentiment);

// Helper: find breakpoints by sweeping a variable
function findBreakpoints(sweepVar, fixedGrowth, fixedSentiment, min, max, step) {
  const sweep = [];
  for (let v = min; v <= max + 0.0001; v = Math.round((v + step) * 1000) / 1000) {
    const g = sweepVar === 'growth'    ? v : fixedGrowth;
    const s = sweepVar === 'sentiment' ? v : fixedSentiment;
    sweep.push({ value: v, recommendation: classify(g, s) });
  }
  const breaks = [];
  for (let i = 1; i < sweep.length; i++) {
    if (sweep[i].recommendation !== sweep[i-1].recommendation) {
      const threshold    = Math.round(((sweep[i-1].value + sweep[i].value) / 2) * 1000) / 1000;
      const currentValue = sweepVar === 'growth' ? fixedGrowth : fixedSentiment;
      const distFromCurrent = Math.abs(threshold - currentValue);
      breaks.push({
        transition:          `${sweep[i-1].recommendation} → ${sweep[i].recommendation}`,
        threshold_approx:    threshold,
        direction:           sweep[i].value > currentValue ? 'MUST_INCREASE_TO_TRIGGER' : 'BREAKS_IF_DECREASES',
        distance_from_current: Math.round(distFromCurrent * 1000) / 1000,
        is_nearest:          false
      });
    }
  }
  // Mark nearest breakpoint
  if (breaks.length > 0) {
    const nearestIdx = breaks.reduce((ni, b, i, arr) =>
      b.distance_from_current < arr[ni].distance_from_current ? i : ni, 0);
    breaks[nearestIdx].is_nearest = true;
  }
  return breaks;
}

// Sweep sentiment (0.00 → 1.00, step 0.05)
const sentimentBreakpoints = findBreakpoints('sentiment', currentGrowth, currentSentiment, 0.00, 1.00, 0.05);

// Sweep growth (-0.10 → 0.60, step 0.05)
const growthBreakpoints = findBreakpoints('growth', currentGrowth, currentSentiment, -0.10, 0.60, 0.05);

// Sensitivity scoring: how many breakpoints lie within ±0.15 of current values
const sentimentBreaksNearby = sentimentBreakpoints.filter(b => b.distance_from_current <= 0.15).length;
const growthBreaksNearby    = growthBreakpoints.filter(b => b.distance_from_current    <= 0.10).length;
const primaryDriver         = sentimentBreaksNearby >= growthBreaksNearby ? 'SENTIMENT' : 'GROWTH';

// Stability score: distance from nearest breakpoints (1.0 = very stable, 0.0 = at a breakpoint)
const minSentDist   = sentimentBreakpoints.length > 0 ? Math.min(...sentimentBreakpoints.map(b => b.distance_from_current)) : 0.50;
const minGrowthDist = growthBreakpoints.length    > 0 ? Math.min(...growthBreakpoints.map(b => b.distance_from_current))    : 0.50;
const stabilityScore = Math.round(Math.min(1, (minSentDist * 2.0 + minGrowthDist * 3.0) / 2.5) * 100) / 100;

// Two-way stress tests: what does ±10% change in each variable cause?
const stressTests = [
  { scenario: 'Sentiment −10%',  g: currentGrowth,    s: Math.max(0, currentSentiment - 0.10), result: classify(currentGrowth, Math.max(0, currentSentiment - 0.10))   },
  { scenario: 'Sentiment +10%',  g: currentGrowth,    s: Math.min(1, currentSentiment + 0.10), result: classify(currentGrowth, Math.min(1, currentSentiment + 0.10))   },
  { scenario: 'Growth −10pp',    g: currentGrowth - 0.10, s: currentSentiment,                  result: classify(currentGrowth - 0.10, currentSentiment)                 },
  { scenario: 'Growth +10pp',    g: currentGrowth + 0.10, s: currentSentiment,                  result: classify(currentGrowth + 0.10, currentSentiment)                 },
  { scenario: 'Both −10%',       g: currentGrowth - 0.10, s: Math.max(0, currentSentiment - 0.10), result: classify(currentGrowth - 0.10, Math.max(0, currentSentiment - 0.10)) },
  { scenario: 'Both +10%',       g: currentGrowth + 0.10, s: Math.min(1, currentSentiment + 0.10), result: classify(currentGrowth + 0.10, Math.min(1, currentSentiment + 0.10)) }
].map(t => ({
  scenario: t.scenario,
  result:   t.result,
  changed:  t.result !== baseRecommendation,
  delta:    t.result !== baseRecommendation ? `${baseRecommendation} → ${t.result}` : 'No change'
}));

// Number of stress tests that triggered a recommendation change
const stressBreachCount = stressTests.filter(t => t.changed).length;
const stressResiliency  = stressBreachCount === 0 ? 'HIGH' : stressBreachCount <= 2 ? 'MEDIUM' : 'LOW';

const nearestSentBreak = sentimentBreakpoints.find(b => b.is_nearest);
const nearestGrowthBreak = growthBreakpoints.find(b => b.is_nearest);

let keyInsight;
if (nearestSentBreak && nearestSentBreak.distance_from_current < 0.10) {
  keyInsight = `🚨 HIGH SENSITIVITY: Decision is ${(nearestSentBreak.distance_from_current * 100).toFixed(0)} sentiment-points from a change (${nearestSentBreak.transition}). Primary driver: ${primaryDriver}.`;
} else if (stabilityScore > 0.7) {
  keyInsight = `✅ STABLE: Current recommendation (${baseRecommendation}) is robust. Nearest trigger is ${(minSentDist * 100).toFixed(0)} sentiment-points away. Primary driver: ${primaryDriver}.`;
} else {
  keyInsight = `⚠️ MODERATE SENSITIVITY: ${primaryDriver} is the primary driver. ${nearestSentBreak ? `Sentiment threshold: ${nearestSentBreak.transition} at ~${nearestSentBreak.threshold_approx}` : ''}. Stability: ${stabilityScore}.`;
}

return [{ json: {
  ...data,
  sim3_threshold_break: {
    simulation:          'THRESHOLD_BREAK',
    current_state:       { recommendation: baseRecommendation, growth: currentGrowth, sentiment: currentSentiment },
    sentiment_breakpoints: sentimentBreakpoints,
    growth_breakpoints:  growthBreakpoints,
    stress_tests:        stressTests,
    sensitivity: {
      sentiment_breaks_nearby: sentimentBreaksNearby,
      growth_breaks_nearby:    growthBreaksNearby,
      primary_driver:          primaryDriver,
      stress_resiliency:       stressResiliency,
      stress_breach_count:     `${stressBreachCount}/6`
    },
    stability_score:     stabilityScore,
    key_insight:         keyInsight
  }
} }];

// ─── AGGREGATE ENGINE: Combine all 3 simulations into a final verdict ─────────
const data = $input.first().json;
const sim1 = data.sim1_growth_sentiment;
const sim2 = data.sim2_risk_appetite;
const sim3 = data.sim3_threshold_break;

// Convert signals to numeric scores (1–5 scale)
const signalScores = {
  'STRONG_BUY':5.0, 'BUY':4.2, 'FUNDAMENTAL_BUY':3.8,
  'HOLD_WATCH':3.2, 'HOLD':3.0, 'UNDERPERFORM':2.2,
  'BUBBLE_RISK':1.8, 'SELL':1.5, 'STRONG_SELL':1.0
};
const recScores = {
  'ENTER_FULL_POSITION':5.0, 'ENTER_PARTIAL_POSITION':3.8,
  'WATCHLIST_ONLY':2.5, 'AVOID':1.0
};

// Weighted scoring: Sim1 most important (market signal), Sim2 next (fit), Sim3 as risk modifier
const s1Raw    = (signalScores[sim1.output.signal] || 3.0) * sim1.output.confidence;
const s2Raw    = recScores[sim2.recommendation] || 3.0;
const s3Raw    = sim3.stability_score * 5.0;

const weights  = { sim1: 0.45, sim2: 0.35, sim3: 0.20 };
const rawScore = (s1Raw * weights.sim1) + (s2Raw * weights.sim2) + (s3Raw * weights.sim3);
const score    = Math.round(Math.min(5.0, Math.max(1.0, rawScore)) * 100) / 100;

const finalRecommendation =
  score >= 4.2 ? 'STRONG_BUY'  :
  score >= 3.6 ? 'BUY'         :
  score >= 2.8 ? 'HOLD'        :
  score >= 1.8 ? 'SELL'        : 'STRONG_SELL';

// ── Probabilistic Scenario Engine ────────────────────────────────────────────
const norm           = score / 5.0;
const thorizonMult   = data.time_horizon === '5year' ? 3.0 : data.time_horizon === '3month' ? 0.25 : 1.0;
const baseReturn     = (score - 3.0) * 18;  // % return expected per year at base

const bestCaseProb   = Math.round(Math.min(65, Math.max(5,  norm * 60 + 5)));
const worstCaseProb  = Math.round(Math.min(65, Math.max(5, (1 - norm) * 55 + 5)));
const expectedProb   = 100 - bestCaseProb - worstCaseProb;

const scenarios = {
  best_case: {
    probability:    bestCaseProb,
    label:          'All tailwinds materialise',
    return_estimate:`+${Math.round((baseReturn + 28) * thorizonMult)}%`,
    conditions:     ['Revenue growth beats estimates', 'Positive sentiment momentum', 'Macro conditions remain favourable', 'No sector disruptions']
  },
  expected_case: {
    probability:    expectedProb,
    label:          'Base case — current trajectory continues',
    return_estimate:`${baseReturn >= 0 ? '+' : ''}${Math.round(baseReturn * thorizonMult)}%`,
    conditions:     ['Current growth rate maintained', 'Sentiment stable', 'Normal market conditions', 'No major earnings surprises']
  },
  worst_case: {
    probability:    worstCaseProb,
    label:          'Headwinds emerge',
    return_estimate:`-${Math.round((Math.abs(baseReturn) + 22) * thorizonMult)}%`,
    conditions:     ['Sentiment deteriorates sharply', 'Revenue misses estimates', 'Macro headwinds', 'Sector rotation away']
  }
};

// ── Risk Flag Engine ──────────────────────────────────────────────────────────
const riskFlags = [];
if (sim1.conflict_detected)                                  riskFlags.push({ severity:'MEDIUM', flag:'Growth–Sentiment conflict detected',            action:'Consider scaling in gradually' });
if (sim1.bubble_risk_score > 0.60)                           riskFlags.push({ severity:'HIGH',   flag:`Bubble risk score: ${sim1.bubble_risk_score}`,  action:'Avoid new positions; set tight stop-loss' });
if (sim3.stability_score < 0.40)                             riskFlags.push({ severity:'HIGH',   flag:'Recommendation near multiple breakpoints',      action:'Monitor daily; do not hold large position' });
if (sim3.sensitivity.sentiment_breaks_nearby > 2)            riskFlags.push({ severity:'MEDIUM', flag:'Highly sentiment-sensitive — 3+ triggers nearby', action:'Watch social/news sentiment closely' });
if (data.pe_ratio > 60 && data.revenue_growth < 0.20)        riskFlags.push({ severity:'HIGH',   flag:`P/E ${data.pe_ratio}x not justified by ${Math.round(data.revenue_growth*100)}% growth`, action:'Valuations stretched — wait for pullback' });
if (data.debt_equity > 1.0)                                  riskFlags.push({ severity:'MEDIUM', flag:`Elevated D/E ratio: ${data.debt_equity}`,        action:'Monitor debt levels and cash flow' });
if (parseInt(sim3.sensitivity.stress_breach_count) > 4)      riskFlags.push({ severity:'HIGH',   flag:'Low stress resiliency — 5+ scenarios trigger change', action:'Only trade with defined risk limits' });

// ── Confidence Score ──────────────────────────────────────────────────────────
const confidenceInputs  = [sim1.output.confidence, sim2.weighted_pass_rate, sim3.stability_score];
const overallConfidence = Math.round(confidenceInputs.reduce((a, b) => a + b, 0) / 3 * 100);

return [{ json: {
  ...data,
  aggregate: {
    final_recommendation: finalRecommendation,
    score,
    score_label:          `${score}/5.0`,
    confidence_pct:       overallConfidence,
    simulation_weights:   weights,
    component_scores:     { sim1_weighted: Math.round(s1Raw * weights.sim1 * 100)/100, sim2_weighted: Math.round(s2Raw * weights.sim2 * 100)/100, sim3_weighted: Math.round(s3Raw * weights.sim3 * 100)/100 },
    scenarios,
    risk_flags:           riskFlags,
    risk_flag_count:      riskFlags.length,
    primary_risk_driver:  sim3.sensitivity.primary_driver,
    key_signals: [
      sim1.key_insight,
      sim2.key_insight,
      sim3.key_insight
    ].filter(Boolean)
  }
} }];

// ─── RESPONSE PARSER: Extract structured insights from Groq (OpenAI format) ───
const apiResponse = $input.first().json;
// Retrieve full simulation data from the last code node before the HTTP call
const prevData    = $('📝 Build AI Prompt').first().json;

// Groq uses OpenAI-compatible format: choices[0].message.content
let aiText = '';
if (apiResponse.choices && Array.isArray(apiResponse.choices) && apiResponse.choices.length > 0) {
  aiText = apiResponse.choices[0]?.message?.content || '';
} else if (apiResponse.error) {
  // Groq error response
  throw new Error(`Groq API Error: ${apiResponse.error.message || JSON.stringify(apiResponse.error)}`);
}

// Parse JSON — strip potential markdown fences if the model added them
let aiInsights = {};
try {
  const cleaned = aiText
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```\s*$/, '')
    .trim();
  aiInsights = JSON.parse(cleaned);
} catch (parseErr) {
  // Fallback: construct a basic insights object from raw text
  console.error('Groq JSON parse failed:', parseErr.message);
  aiInsights = {
    executive_summary:    aiText.substring(0, 300) || 'AI analysis unavailable — review quantitative data.',
    bull_case:            'See simulation results for fundamental signals.',
    bear_case:            'See risk flags for downside scenarios.',
